#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int n,a[N],l,r,len,c[3*N];
long long s[N],ls[3*N],ans;
map<long long,int> id;

int lowbit(int x){
    return x&(-x);
}

void add(int x,int k){
    for(;x<=len;x+=lowbit(x))
        c[x]+=k;
}

int ask(int x){
    int sum=0;
    for(;x;x-=lowbit(x))
        sum+=c[x];
    return sum;
}

int main(){
    int tot=0;
    scanf("%d%d%d",&n,&l,&r);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        s[i]=s[i-1]+a[i];
        ls[++tot]=s[i-1]+l,ls[++tot]=s[i-1]+r+1,ls[++tot]=s[i];
    }
    sort(ls+1,ls+tot+1);
    len=unique(ls+1,ls+tot+1)-ls-1;
    for(int i=1;i<=len;i++)
        id[ls[i]]=i;
    for(int i=1;i<=n;i++){
        add(id[s[i-1]+l],1),add(id[s[i-1]+r+1],-1);
        ans+=ask(id[s[i]]);
    }
    printf("%lld",ans);
    return 0;
}
